import React, { useRef, useEffect } from 'react';
import './ChatInput.css';

const SUGGESTIONS = [
  'Which airline has the highest average fare?',
  'Show bookings by class (Economy, Business, First)',
  'What is the cancellation rate per airline?',
  'Top 5 routes by number of bookings',
  'Monthly booking trend for 2023',
  'Revenue breakdown by extras type',
  'Average flight duration by airline',
  'Which terminal has most departures?',
];

export default function ChatInput({ input, setInput, onSend, isLoading, onCancel }) {
  const ref = useRef(null);

  useEffect(() => {
    if (ref.current) {
      ref.current.style.height = 'auto';
      ref.current.style.height = Math.min(ref.current.scrollHeight, 140) + 'px';
    }
  }, [input]);

  const handleKey = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); onSend(input); }
  };

  return (
    <div className="chat-input-area">
      <div className="suggestions-row">
        {SUGGESTIONS.map((s, i) => (
          <button key={i} className="suggestion-chip" onClick={() => onSend(s)} disabled={isLoading}>
            {s}
          </button>
        ))}
      </div>

      <div className="input-bar">
        <span className="prompt-glyph">›</span>
        <textarea
          ref={ref}
          className="chat-textarea"
          placeholder="Ask anything about the flight data…  (Enter to send)"
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKey}
          disabled={isLoading}
          rows={1}
        />
        {isLoading ? (
          <button className="send-btn cancel" onClick={onCancel}>
            <span className="spinner" /> Cancel
          </button>
        ) : (
          <button className="send-btn" onClick={() => onSend(input)} disabled={!input.trim()}>
            Send
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <line x1="22" y1="2" x2="11" y2="13"/>
              <polygon points="22 2 15 22 11 13 2 9 22 2"/>
            </svg>
          </button>
        )}
      </div>

      <div className="input-footer">
        <span>FlightIQ · Groq LLaMA + pandas</span>
        <span>Shift+Enter for new line</span>
      </div>
    </div>
  );
}
